document.addEventListener('DOMContentLoaded', function () {

 if (window.location.pathname.indexOf('/admin') !== 0) return;


 const toastContainer = document.createElement('div');
 toastContainer.className = 'admin-alert-toast-container';
 document.body.appendChild(toastContainer);


 const processedAlertIds = new Set();

 function scanSecurityIncidentsTelemetry() {
 fetch('/api/admin/security-alerts', {
 method: 'GET',
 headers: { 'X-Requested-With': 'XMLHttpRequest' }
 })
 .then(response => {
 if (!response.ok) throw new Error('API Access unauthorized or dropped');
 return response.json();
 })
 .then(data => {
 if (data.status === 'success' && Array.isArray(data.alerts)) {
 data.alerts.forEach(alert => {
 const alertId = parseInt(alert.id, 10);
 

 if (processedAlertIds.has(alertId)) return;
 processedAlertIds.add(alertId);


 if (processedAlertIds.size > 10 && alertId) {
 spawnSecurityToastAlert(alert);
 }
 });
 }
 })
 .catch(err => console.warn('Security monitor channel disconnect:', err));
 }

 function spawnSecurityToastAlert(alert) {
 const toast = document.createElement('div');
 toast.className = 'security-alert-toast-item';
 
 toast.innerHTML = `
 <div class="security-alert-toast-header">
 <span>⚠️ КРИТИЧЕСКАЯ АКТИВНОСТЬ</span>
 <span class="security-alert-toast-time">${alert.created_at.split(' ')[1]}</span>
 </div>
 <div class="security-alert-toast-body">
 <strong>Действие:</strong> ${alert.action}<br>
 ${alert.description}<br>
 <strong>Атакующий IP:</strong> <span class="security-alert-toast-ip">${alert.ip_address}</span>
 </div>
 `;

 toastContainer.appendChild(toast);


 setTimeout(() => {
 toast.style.opacity = '0';
 toast.style.transform = 'translateY(-10px)';
 toast.style.transition = 'all 0.4s ease';
 setTimeout(() => toast.remove(), 400);
 }, 8000);
 }


 scanSecurityIncidentsTelemetry();
 setInterval(scanSecurityIncidentsTelemetry, 10000);
});

;


;


function updateHeaderNotificationCount() {
 fetch('/api/notifications/count')
 .then(response => {

 if (response.status === 401) {
 const badge = document.getElementById('header-notification-badge');
 if (badge) badge.style.display = 'none';
 return null; // Прерываем цепочку
 }
 

 if (!response.ok) {
 throw new Error('HTTP ' + response.status);
 }
 
 return response.json();
 })
 .then(data => {
 if (!data) return; // Был ответ 401
 
 const badge = document.getElementById('header-notification-badge');
 if (!badge) return;
 
 if (data.count > 0) {
 badge.textContent = data.count > 99 ? '99+' : data.count;
 badge.style.display = 'block';
 } else {
 badge.style.display = 'none';
 }
 })
 .catch(error => {

 console.error('Ошибка получения счетчика уведомлений:', error);
 });
}


document.addEventListener('DOMContentLoaded', () => {
 updateHeaderNotificationCount();
 

 setInterval(updateHeaderNotificationCount, 60000);
 

 document.addEventListener('click', function(e) {
 const link = e.target.closest('.notification-link');
 if (!link) return;
 
 const notificationId = link.dataset.notificationId;
 if (!notificationId) return;
 

 e.preventDefault();
 
 const destinationUrl = link.href;
 

 const csrfToken = document.querySelector('meta[name="csrf-token"]')?.content 
 || document.querySelector('input[name="csrf_token"]')?.value 
 || '';
 

 fetch(`/notifications/${notificationId}/read`, {
 method: 'POST',
 headers: {
 'Content-Type': 'application/x-www-form-urlencoded',
 'X-CSRF-Token': csrfToken,
 'X-Requested-With': 'XMLHttpRequest'
 }
 })
 .then(response => {

 updateHeaderNotificationCount();
 

 const notificationItem = link.closest('.notification-item');
 if (notificationItem) {
 notificationItem.classList.remove('notification-unread');
 notificationItem.classList.add('notification-read');
 }
 

 window.location.href = destinationUrl;
 })
 .catch(error => {
 console.error('Ошибка при отметке уведомления:', error);

 window.location.href = destinationUrl;
 });
 });
});


document.getElementById('mark-all-read-btn')?.addEventListener('click', function(e) {
 e.preventDefault();
 
 const csrfToken = document.querySelector('meta[name="csrf-token"]')?.content 
 || document.querySelector('input[name="csrf_token"]')?.value 
 || '';
 
 fetch('/notifications/mark-all-read', {
 method: 'POST',
 headers: {
 'Content-Type': 'application/x-www-form-urlencoded',
 'X-CSRF-Token': csrfToken,
 'X-Requested-With': 'XMLHttpRequest'
 }
 })
 .then(response => {
 if (response.ok) {
 location.reload();
 }
 })
 .catch(error => {
 console.error('Ошибка при отметке всех уведомлений:', error);
 });
});


;


document.addEventListener('DOMContentLoaded', function() {




 document.addEventListener('submit', function(event) {
 const form = event.target;


 if (form.action && form.action.indexOf('/vote/') !== -1) {
 return true;
 }


 if (form.dataset.isSubmitting === 'true') {
 event.preventDefault();
 return false;
 }


 if (form.classList.contains('js-comment-delete-form')) {
 const confirmed = confirm('Вы уверены, что хотите удалить этот комментарий?');
 if (!confirmed) {
 event.preventDefault();
 return false;
 }
 }


 form.dataset.isSubmitting = 'true';

 const submitBtn = form.querySelector('button[type="submit"]');
 if (submitBtn) {
 submitBtn.disabled = true;
 }
 });




 const replyButtons = document.querySelectorAll('.comment-reply-link');
 const editButtons = document.querySelectorAll('.comment-edit-trigger');
 const parentIdInput = document.getElementById('form-parent-id');
 const cancelBtn = document.getElementById('btn-cancel-reply');
 const commentForm = document.getElementById('main-comment-form');
 const textarea = document.getElementById('form-comment-textarea');
 const formContainer = document.getElementById('comment-form-container');




 if (commentForm && replyButtons.length > 0) {

 replyButtons.forEach(button => {
 button.addEventListener('click', function(e) {
 e.preventDefault();


 document.querySelectorAll('.comment-dynamic-edit-form').forEach(f => f.remove());
 document.querySelectorAll('.comment_text').forEach(t => t.style.display = 'block');


 const commentId = this.getAttribute('href').replace('#reply-to-', '');


 const parentComment = this.closest('li.comment');
 if (!parentComment) return;


 const authorLink = parentComment.querySelector('.comment_meta a');
 const authorName = authorLink ? authorLink.innerText : '';


 if (parentIdInput) {
 parentIdInput.value = commentId;
 }


 if (cancelBtn) {
 cancelBtn.style.display = 'inline-block';
 }


 parentComment.parentNode.insertBefore(commentForm, parentComment.nextSibling);


 if (textarea) {
 textarea.focus();
 }
 });
 });


 if (cancelBtn) {
 cancelBtn.addEventListener('click', function() {

 if (parentIdInput) {
 parentIdInput.value = '';
 }


 cancelBtn.style.display = 'none';


 if (formContainer) {
 formContainer.appendChild(commentForm);
 }


 if (textarea) {
 textarea.value = '';
 }
 });
 }
 }




 editButtons.forEach(button => {
 button.addEventListener('click', function(e) {
 e.preventDefault();

 const commentId = this.getAttribute('data-id');


 const commentLi = this.closest('li.comment');
 if (!commentLi) return;


 const textBlock = document.getElementById(`comment-text-content-${commentId}`);
 if (!textBlock) return;


 if (commentLi.querySelector('.comment-dynamic-edit-form')) return;


 textBlock.style.display = 'none';


 const currentText = textBlock.getAttribute('data-raw') || '';


 const csrfInput = document.querySelector('input[name="csrf_token"]');
 const csrfToken = csrfInput ? csrfInput.value : '';


 const editForm = document.createElement('form');
 editForm.action = `/comments/${commentId}/edit`;
 editForm.method = 'POST';
 editForm.className = 'comment-dynamic-edit-form';

 editForm.innerHTML = `
 <input type="hidden" name="csrf_token" value="${escapeHtml(csrfToken)}">
 <textarea name="comment_text" required>${escapeHtml(currentText)}</textarea>
 <div class="comment_actions">
 <button type="submit">Сохранить</button>
 <span class="divider">|</span>
 <button type="button" class="comment-edit-cancel btn-link">Отмена</button>
 </div>
 `;


 textBlock.parentNode.insertBefore(editForm, textBlock.nextSibling);


 const editTextarea = editForm.querySelector('textarea');
 if (editTextarea) {
 editTextarea.focus();
 }


 editForm.querySelector('.comment-edit-cancel').addEventListener('click', function() {
 editForm.remove();
 textBlock.style.display = 'block';
 });
 });
 });




 function escapeHtml(text) {
 const div = document.createElement('div');
 div.textContent = text;
 return div.innerHTML;
 }


 document.querySelectorAll('.js-confirm-delete').forEach(function(form) {
 form.addEventListener('submit', function(e) {
 const message = this.getAttribute('data-confirm-message') || 'Вы уверены?';
 if (!confirm(message)) {
 e.preventDefault();
 return false;
 }
 });
 });

});

;

(function() {
 'use strict';

 function getCsrfToken() {
 const meta = document.querySelector('meta[name="csrf-token"]');
 return meta ? meta.getAttribute('content') : '';
 }

 function showNotification(message, type = 'info') {
 const notification = document.createElement('div');
 notification.className = `notification notification-${type}`;
 notification.textContent = message;
 notification.style.cssText = `
 position: fixed; top: 20px; right: 20px; padding: 15px 20px;
 background: ${type === 'error' ? '#f44336' : '#4CAF50'};
 color: white; border-radius: 4px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);
 z-index: 10000; animation: slideIn 0.3s ease-out; font-family: sans-serif;
 `;
 document.body.appendChild(notification);
 setTimeout(() => {
 notification.style.animation = 'slideOut 0.3s ease-out';
 setTimeout(() => notification.remove(), 300);
 }, 3000);
 }

 if (!document.getElementById('notification-styles')) {
 const style = document.createElement('style');
 style.id = 'notification-styles';
 style.textContent = `
 @keyframes slideIn { from { transform: translateX(100%); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
 @keyframes slideOut { from { transform: translateX(0); opacity: 1; } to { transform: translateX(100%); opacity: 0; } }
 `;
 document.head.appendChild(style);
 }


 async function postJson(endpoint, data) {
 const csrfToken = getCsrfToken();
 if (!csrfToken) throw new Error('CSRF-токен не найден. Обновите страницу.');


 const url = window.location.origin + endpoint;

 const formData = new URLSearchParams();
 formData.append('csrf_token', csrfToken);
 for (const [key, value] of Object.entries(data)) {
 formData.append(key, value);
 }

 const response = await fetch(url, {
 method: 'POST',
 headers: {
 'Content-Type': 'application/x-www-form-urlencoded',
 'X-Requested-With': 'XMLHttpRequest'
 },
 body: formData.toString(),

 redirect: 'manual' 
 });


 if (response.status === 302 || response.status === 301) {
 const redirectUrl = response.headers.get('location');
 throw new Error(`Сервер попытался сделать редирект на: ${redirectUrl}. Проверьте CSRF или авторизацию.`);
 }

 const text = await response.text();
 try {
 return JSON.parse(text);
 } catch (e) {
 console.error('Сервер вернул не JSON:', text);
 throw new Error('Некорректный ответ сервера: ' + text.substring(0, 100));
 }
 }


 document.getElementById('btn-add-filter')?.addEventListener('click', async function() {
 const tagId = document.getElementById('tag-select').value;
 if (!tagId) {
 showNotification('Выберите тег из списка', 'error');
 return;
 }

 const button = this;
 button.disabled = true;
 const originalText = button.textContent;
 button.textContent = 'Добавление...';

 try {
 const result = await postJson('/filters/add', { tag_id: tagId });
 if (result.success) {
 showNotification(result.message, 'success');
 setTimeout(() => location.reload(), 800);
 } else {
 showNotification(result.message || 'Ошибка', 'error');
 }
 } catch (error) {
 console.error('Ошибка:', error);
 showNotification(error.message, 'error');
 } finally {
 button.disabled = false;
 button.textContent = originalText;
 }
 });


 document.querySelectorAll('.btn-remove-filter').forEach(btn => {
 btn.addEventListener('click', async function() {
 if (!confirm('Удалить этот тег из фильтров?')) return;

 const tagId = this.closest('.filter-item').dataset.tagId;
 const button = this;
 button.disabled = true;
 const originalText = button.textContent;
 button.textContent = '...';

 try {
 const result = await postJson('/filters/remove', { tag_id: tagId });
 if (result.success) {
 showNotification(result.message, 'success');
 setTimeout(() => location.reload(), 800);
 } else {
 showNotification(result.message || 'Ошибка', 'error');
 }
 } catch (error) {
 console.error('Ошибка:', error);
 showNotification(error.message, 'error');
 } finally {
 button.disabled = false;
 button.textContent = originalText;
 }
 });
 });
})();
;


document.addEventListener('DOMContentLoaded', function () {
 const trigger = document.getElementById('user-dropdown-trigger');
 const menu = document.getElementById('user-dropdown-menu');
 const wrapper = document.getElementById('user-dropdown-wrapper');

 if (!trigger || !menu) return; // Выходим, если пользователь — гость


 trigger.addEventListener('click', function (event) {
 event.stopPropagation(); // Предотвращаем всплытие события вверх к документу
 
 const isActive = menu.classList.contains('active');
 
 if (isActive) {
 menu.classList.remove('active');
 wrapper.classList.remove('active');
 trigger.setAttribute('aria-expanded', 'false');
 } else {
 menu.classList.add('active');
 wrapper.classList.add('active');
 trigger.setAttribute('aria-expanded', 'true');
 }
 });


 document.addEventListener('click', function (event) {

 if (!wrapper.contains(event.target)) {
 if (menu.classList.contains('active')) {
 menu.classList.remove('active');
 wrapper.classList.remove('active');
 trigger.setAttribute('aria-expanded', 'false');
 }
 }
 });
});

;


document.addEventListener('DOMContentLoaded', function () {

 const registerForm = document.querySelector('form[action="/register"]');
 const loginForm = document.querySelector('form[action="/login"]');

 
 function showError(form, message) {

 let oldAlert = form.querySelector('.js-error-alert');
 if (oldAlert) oldAlert.remove();


 const alertDiv = document.createElement('div');
 alertDiv.className = 'js-error-alert';
 alertDiv.style.color = '#e74c3c';
 alertDiv.style.background = '#fdf2f2';
 alertDiv.style.padding = '10px';
 alertDiv.style.border = '1px solid #f8b4b4';
 alertDiv.style.marginBottom = '15px';
 alertDiv.style.borderRadius = '4px';
 alertDiv.style.fontSize = '14px';
 alertDiv.innerText = message;


 form.insertBefore(alertDiv, form.firstChild);
 }


 if (registerForm) {
 registerForm.addEventListener('submit', function (event) {
 const nameInput = registerForm.querySelector('input[name="name"]');
 const emailInput = registerForm.querySelector('form input[name="email"]');
 const passwordInput = registerForm.querySelector('input[name="password"]');


 if (nameInput && nameInput.value.trim().length < 2) {
 event.preventDefault(); // Halt form submission cycle
 showError(registerForm, 'Имя пользователя должно быть не менее 2 символов.');
 nameInput.focus();
 return;
 }


 const emailRegEx = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
 if (emailInput && !emailRegEx.test(emailInput.value.trim())) {
 event.preventDefault();
 showError(registerForm, 'Пожалуйста, введите корректный email адрес.');
 emailInput.focus();
 return;
 }


 if (passwordInput && passwordInput.value.length < 6) {
 event.preventDefault(); 
 showError(registerForm, 'Пароль должен состоять минимум из 6 символов.');
 passwordInput.focus();
 return;
 }
 });
 }


 if (loginForm) {
 loginForm.addEventListener('submit', function (event) {
 const passwordInput = loginForm.querySelector('input[name="password"]');

 if (passwordInput && passwordInput.value.length < 6) {
 event.preventDefault();
 showError(loginForm, 'Введен слишком короткий пароль. Минимум — 6 символов.');
 passwordInput.focus();
 return;
 }
 });
 }
});

;


document.addEventListener('DOMContentLoaded', function() {


 document.addEventListener('submit', function(event) {
 const form = event.target;


 if (!form.action || form.action.indexOf('/vote/') === -1) {
 return;
 }

 event.preventDefault();


 if (form.dataset.ajaxSubmitting === 'true') {
 return;
 }


 const wrapper = form.closest('.voters');
 if (!wrapper) {
 return;
 }


 form.dataset.ajaxSubmitting = 'true';

 const formData = new FormData(form);

 fetch(form.action, {
 method: 'POST',
 body: formData,
 headers: {
 'X-Requested-With': 'XMLHttpRequest'
 }
 })
 .then(response => {
 if (response.status === 401) {
 alert('Пожалуйста, войдите в аккаунт, чтобы голосовать.');
 throw new Error('Unauthorized');
 }

 if (!response.ok) {
 return response.json().then(errData => {
 alert(errData.message || 'Ошибка обработки голоса.');
 throw new Error('Server error');
 });
 }

 return response.json();
 })
 .then(data => {
 if (data.status !== 'success') {
 return;
 }


 const scoreEl = wrapper.querySelector('.score');
 if (scoreEl) {
 scoreEl.textContent = data.new_score;
 }


 const buttons = wrapper.querySelectorAll('.upvoter');
 buttons.forEach(btn => btn.classList.remove('upvoted'));



 if (data.vote_state === 1) {
 const upBtn = wrapper.querySelector('form[action*="/up"] .upvoter');
 if (upBtn) upBtn.classList.add('upvoted');
 } else if (data.vote_state === -1) {
 const downBtn = wrapper.querySelector('form[action*="/down"] .upvoter');
 if (downBtn) downBtn.classList.add('upvoted');
 }
 })
 .catch(error => {
 console.warn('Voting error:', error);
 })
 .finally(() => {

 form.dataset.ajaxSubmitting = 'false';
 });
 });

});
